// Obtener datos con fallback si algún nodo no ejecutó aún
let contactosResp = {}, leadsResp = {}, enviosResp = {};
try { contactosResp = $('Leer Contactos').first().json; } catch(e) {}
try { leadsResp = $('Leer Leads').first().json; } catch(e) {}
try { enviosResp = $('Leer Envios de Hoy').first().json; } catch(e) {}

function parseDoc(doc) {
  const f = doc.fields || {};
  return {
    nombre: f.nombre?.stringValue || 'Cliente',
    email: (f.email?.stringValue || '').toLowerCase().trim(),
    interes: (f.interes?.stringValue || f.propiedad?.stringValue || 'nave').toLowerCase()
  };
}

// Validacion basica de formato de email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const todos = [
  ...(contactosResp.documents || []),
  ...(leadsResp.documents || [])
].map(parseDoc).filter(c => c.email && emailRegex.test(c.email));

const hoy = new Date().toISOString().slice(0, 10);
const enviadosHoy = new Set(
  (enviosResp.documents || [])
    .map(d => d.fields || {})
    .filter(f => (f.fecha?.stringValue || '').startsWith(hoy))
    .map(f => (f.email?.stringValue || '').toLowerCase())
    .filter(Boolean)
);

const emailsVistos = new Set();
const pendientes = todos.filter(c => {
  if (!c.email || emailsVistos.has(c.email) || enviadosHoy.has(c.email)) return false;
  emailsVistos.add(c.email);
  return true;
});

console.log(`Total: ${todos.length} | Enviados hoy: ${enviadosHoy.size} | Pendientes: ${pendientes.length}`);
return pendientes.map(c => ({ json: c }));

